import { TZDateMini } from '@date-fns/tz';
import clsx from 'clsx';
import { useMemo } from 'react';
import { useIntl } from 'react-intl';

import Spacings from '@dynatrace/strato-design-tokens/spacings';
import { getTimezone } from '@dynatrace-sdk/user-preferences';

import * as styles from './TimeframeSelectorOverlay.sty.js';
import { Button } from '../../../../buttons/button/Button.js';
import { TIMEFRAME_SELECTOR_DOCUMENTATION_URL } from '../../../../core/external-links.js';
import { useTimeframeSelectorStore } from '../../../../core/time/timeframeStore/useTimeframeStore.js';
import { getSafeRegionalFormat } from '../../../../forms/forms-core/time/helpers.js';
import { Divider } from '../../../../layouts/divider/Divider.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { globalSprinkles } from '../../../../styles/safe-sprinkles.js';
import { ExternalLink } from '../../../../typography/external-link/ExternalLink.js';
import { Text } from '../../../../typography/text/Text.js';
import { TIMEFRAME_SELECTOR_MESSAGES } from '../../constants/timeframeSelectorMessages.js';
import type { TimeframeSelectorProps } from '../../TimeframeSelector.types.js';

export const TimeframeSelectorOverlayFooter = (
  props: Pick<TimeframeSelectorProps, 'clearable'>,
) => {
  /* eslint-disable @typescript-eslint/no-deprecated */
  const { clearable } = props;
  const intl = useIntl();

  const setValue = useTimeframeSelectorStore(
    (state) => state.setTimeframeSelectorTimeframe,
  );

  const timeZoneWithOffset = useMemo(() => {
    const timeZone = getTimezone();

    const parts = new Intl.DateTimeFormat(getSafeRegionalFormat(), {
      timeZone,
      timeZoneName: 'shortOffset',
    }).formatToParts(TZDateMini.tz(timeZone));
    const partsShortName = new Intl.DateTimeFormat(getSafeRegionalFormat(), {
      timeZone,
      timeZoneName: 'short',
    }).formatToParts(TZDateMini.tz(timeZone));
    const timeZonePart = parts
      ?.find((part) => part.type === 'timeZoneName')
      ?.value.replace('GMT', 'UTC');
    const timeZoneInfo = timeZonePart === 'UTC' ? 'UTC+0' : timeZonePart;
    const timezoneDetails = timeZoneInfo ? ` (${timeZoneInfo})` : '';
    const timeZoneShortName = partsShortName?.find(
      (part) => part.type === 'timeZoneName',
    )?.value;

    return `${timeZoneShortName}${timezoneDetails}`;
  }, []);

  /** Handles the clear selection. Uses the pointerDown event to circumvent triggering the validation onBlur first. */
  function handleClearSelection() {
    setValue(null);
  }

  return (
    <>
      <Divider />
      <Flex
        justifyContent="space-between"
        alignItems="center"
        flexWrap="wrap-reverse"
        flex={1}
        gap={4}
        className={styles.footer}
      >
        <Flex
          justifyContent={clearable ? 'flex-start' : 'space-between'}
          alignItems="center"
          flexShrink={1}
          flexGrow={1}
          className={clsx(globalSprinkles({ paddingLeft: 6 }), {
            [globalSprinkles({ paddingTop: 4, paddingBottom: 4 })]: !clearable,
          })}
        >
          <Text className={styles.hint}>{timeZoneWithOffset}</Text>
          {clearable && <Divider orientation="vertical" />}
          <Text
            as={ExternalLink}
            href={TIMEFRAME_SELECTOR_DOCUMENTATION_URL}
            textStyle="small"
            style={{ paddingRight: Spacings.Size6 }}
            data-dt-name="LearnMore"
          >
            {intl.formatMessage(TIMEFRAME_SELECTOR_MESSAGES.docsLinkText)}
          </Text>
        </Flex>
        {clearable && (
          <Button
            type="reset"
            onPointerDown={handleClearSelection}
            size="condensed"
          >
            {intl.formatMessage(
              TIMEFRAME_SELECTOR_MESSAGES.resetTimeframeButton,
            )}
          </Button>
        )}
      </Flex>
    </>
  );
};

(
  TimeframeSelectorOverlayFooter as typeof TimeframeSelectorOverlayFooter & {
    displayName: string;
  }
).displayName = 'TimeframeSelectorOverlayFooter';
